+    asx_snapshot_buffer s1, s2;
+    uint64_t d1, d2;
+
+    asx_runtime_reset();
+    asx_ghost_reset();
+    asx_trace_reset();
+
+    ASSERT_EQ(asx_snapshot_capture(&s1), ASX_OK);
