+    asx_ghost_reset();
+    asx_trace_reset();
+
+    ASSERT_EQ(asx_snapshot_capture(&s2), ASX_OK);
+    d2 = asx_snapshot_digest(&s2);
+
+    ASSERT_EQ(d1, d2);
+}
